+			item.AgentCounts = &output.AgentCountsResponse{
+				Claude: claudeCount,
+				Codex:  codexCount,
+				Gemini: geminiCount,
+				User:   userCount,
+				Total:  len(panes),
+			}
+		}
+		items[i] = item
+	}
+
+	return output.ListResponse{
